def judgePoint24(cards):
    if len(cards) == 1: return abs(cards[0] - 24) < 1e-6
    for i in range(len(cards)):
        for j in range(len(cards)):
            if i == j: continue
            nxt = [cards[k] for k in range(len(cards)) if k != i and k != j]
            possible = [cards[i] + cards[j], cards[i] - cards[j], cards[j] - cards[i], cards[i] * cards[j]]
            if cards[j] != 0: possible.append(cards[i] / cards[j])
            if cards[i] != 0: possible.append(cards[j] / cards[i])
            for p in possible:
                if self.judgePoint24(nxt + [p]): return True
    return False

